        ("Evolutionary Stability", "The probability that the synthetic circuit maintains its designed function over many generations — mutations that reduce metabolic burden are selected for, meaning evolution actively tries to break engineered systems", False),
        ("Output Fidelity", "The precision and reliability with which the genetic circuit produces the intended biological output — affected by molecular noise, metabolic state, and environmental conditions", False),
        ("Growth Rate", "The speed at which the engineered organism reproduces — determined by the balance between natural growth capacity and the metabolic burden imposed by synthetic circuits", False),
